import { useEditor } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import {
  ToolButtonBold,
  ToolButtonItalic,
  ToolButtonStrike,
  ToolButtonBulletList,
  ToolButtonOrderedList,
  ToolButtonUndo,
  ToolButtonRedo
} from '@/components/shared/EditorTools';

const editor = useEditor({
  extensions: [StarterKit],
  content: '<p>Hello World!</p>'
});

if (!editor) return null;

return (
  <div className="flex gap-1 p-2 border-b">
    <ToolButtonBold editor={editor} />
    <ToolButtonItalic editor={editor} />
    <ToolButtonStrike editor={editor} />
    <div className="w-px h-6 bg-gray-300 mx-1" />
    <ToolButtonBulletList editor={editor} />
    <ToolButtonOrderedList editor={editor} />
    <div className="w-px h-6 bg-gray-300 mx-1" />
    <ToolButtonUndo editor={editor} />
    <ToolButtonRedo editor={editor} />
  </div>
);

import {
  ToolButtonBold,
  ToolButtonItalic,
  ToolButtonStrike,
  ToolButtonCode,
  ToolButtonHeading,
  ToolButtonBulletList,
  ToolButtonOrderedList,
  ToolButtonBlockquote,
  ToolButtonCodeBlock,
  ToolButtonImage,
  ToolButtonHorizontalRule,
  ToolButtonUndo,
  ToolButtonRedo
} from '@/components/shared/EditorTools';

const handleImageUpload = async (file: File) => {
  const formData = new FormData();
  formData.append('image', file);
  const response = await fetch('/api/upload', {
    method: 'POST',
    body: formData
  });
  const { url } = await response.json();
  return url;
};

return (
  <div className="flex flex-wrap gap-1 p-2 border-b">
    {/* Text Formatting */}
    <ToolButtonBold editor={editor} />
    <ToolButtonItalic editor={editor} />
    <ToolButtonStrike editor={editor} />
    <ToolButtonCode editor={editor} />

    {/* Headings */}
    <ToolButtonHeading editor={editor} headingLevel={[1, 2, 3]} />

    {/* Lists */}
    <ToolButtonBulletList editor={editor} />
    <ToolButtonOrderedList editor={editor} />

    {/* Blocks */}
    <ToolButtonBlockquote editor={editor} />
    <ToolButtonCodeBlock editor={editor} />
    <ToolButtonHorizontalRule editor={editor} />

    {/* Media */}
    <ToolButtonImage editor={editor} onUpload={handleImageUpload} />

    {/* History */}
    <ToolButtonUndo editor={editor} />
    <ToolButtonRedo editor={editor} />
  </div>
);

import { ToolButton } from '@/components/shared/EditorTools';
import { LuHighlighter } from 'react-icons/lu';
import type { BaseToolButtonProps } from '@/components/shared/EditorTools/types';

const ToolButtonHighlight = ({ editor }: BaseToolButtonProps) => {
  return (
    <ToolButton
      title="Highlight"
      active={editor.isActive('highlight')}
      onClick={() => editor.chain().focus().toggleHighlight().run()}
    >
      <LuHighlighter />
    </ToolButton>
  );
};

